//@ts-check
class BDSMPlayer {
    constructor(hp, atk, adv_def, critchance, bonuses, tier4, tier5, name = '') {
        this.name = '';
        this.hp = hp;
        this.atk = atk;
        this.adv_def = adv_def;
        this.critchance = critchance;
        this.bonuses = bonuses;
        this.tier4 = tier4;
        this.tier5 = tier5;
        this.name = name;
    }
}

